    @staticmethod
    def get_pixmap(name, size=24, color="#000000"):
        """Returns a QPixmap for the given icon name, size, and hex color."""
        svg_template = IconManager.ICONS.get(name)
        if not svg_template:
            logger.warning(f"Icon '{name}' not found.")
            return QPixmap()
            
        svg_data = svg_template.replace("{color}", color)
        renderer = QSvgRenderer(QByteArray(svg_data.encode('utf-8')))
        
        pixmap = QPixmap(size, size)
        pixmap.fill(Qt.transparent)
        
        painter = QPainter(pixmap)
        renderer.render(painter)
        painter.end()
        
        return pixmap

    @staticmethod
    def get_icon(name, size=24, color="#000000"):
        """Returns a QIcon for the given icon name."""
        return QIcon(IconManager.get_pixmap(name, size, color))
